import api from "./axios";

export const getVehicles = () => api.get("/vehicles");
export const getVehicleById = (id) => api.get(`/vehicles/${id}`);

export const addVehicle = (data) => api.post("/vehicles/add", data); // admin/manager
export const updateVehicle = (id, data) => api.put(`/vehicles/${id}`, data); // admin/manager
export const deleteVehicle = (id) => api.delete(`/vehicles/${id}`); // admin/manager
